command:
const light = game.settings.get("starwarsffg", "dPoolLight"), dark = game.settings.get("starwarsffg", "dPoolDark");
const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: "Points de Destin" },
  content: `<p>Réserve actuelle : <strong>${light} [li] · ${dark} [da]</strong></p>
    <div class="form-group"><label>Jet de début de séance — dés de Force à lancer (1/PJ)</label>
    <input type="number" name="n" value="3" min="0" max="10"/></div>
    <div class="form-group"><label><input type="checkbox" name="remind" checked/> Poster le rappel des usages</label></div>`,
  buttons: [{ action: "roll", label: "Lancer & mettre à jour", default: true,
      callback: (event, button) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(button.form).object },
    { action: "cancel", label: "Fermer" }],
});
if (!fd || fd === "cancel") return;
let msg = "";
if (Number(fd.n) > 0) {
  const roll = new game.ffg.RollFFG(`${Number(fd.n)}df`);
  await roll.evaluate();
  let l = 0, d = 0;
  for (const die of roll.dice) for (const r of die.results) {
    l += r.ffg?.light ?? 0; d += r.ffg?.dark ?? 0;
  }
  if (!l && !d && roll.ffg) { l = roll.ffg.light ?? 0; d = roll.ffg.dark ?? 0; }
  await game.settings.set("starwarsffg", "dPoolLight", l);
  await game.settings.set("starwarsffg", "dPoolDark", d);
  await roll.toMessage({ flavor: "Jet de Destin — début de séance" });
  msg = `<p>Nouvelle réserve : <strong>${l} [li] · ${d} [da]</strong></p>`;
}
if (fd.remind) await ChatMessage.create({ content: `<h3>⭐ Points de Destin</h3>${msg}
  <p><strong>Joueurs [li]</strong> : améliorer 1 dé de son pool · dégrader 1 [di] adverse ·
  activer certains talents · « coup de pouce » narratif validé par le MJ.</p>
  <p><strong>MJ [da]</strong> : améliorer la difficulté d'un test de PJ · améliorer le pool d'un PNJ ·
  déclencher une complication narrative.</p>
  <p style="font-size:.9em">Un point dépensé bascule de l'autre côté de la réserve.</p>` });
